using System.IO;using System.Net;using System.Threading.Tasks;using Azure.Storage.Blobs;using Microsoft.Azure.Functions.Worker;using Microsoft.Azure.Functions.Worker.Http;using Microsoft.Extensions.Logging;namespace ABC_Retail.Functions.Functions{   	// Azure Function to write HTTP POST content to Azure Blob Storage	public static class WriteToBlobFunction	{		[Function("WriteToBlob")]		public static async Task<HttpResponseData> Run(			[HttpTrigger(AuthorizationLevel.Function, "post")] HttpRequestData req,			FunctionContext context)		{			// Get logger instance for logging information			var logger = context.GetLogger("WriteToBlob");			// Retrieve Azure Storage connection string from environment variables			string connectionString = Environment.GetEnvironmentVariable("AzureWebJobsStorage")									  ?? throw new InvalidOperationException("Connection string not found.");			// Create BlobServiceClient to interact with Blob Storage			var blobServiceClient = new BlobServiceClient(connectionString);			// Get a reference to the 'uploads' container and create it if it doesn't exist			var containerClient = blobServiceClient.GetBlobContainerClient("uploads");			await containerClient.CreateIfNotExistsAsync();			// Read the entire request body as the content to be saved in the blob			string fileContent = await new StreamReader(req.Body).ReadToEndAsync();			// Generate a unique file name for the blob			string fileName = $"log_{Guid.NewGuid()}.txt";			// If the request body is empty, write a default message			if (string.IsNullOrEmpty(fileContent))			{				fileContent = $"Empty content written at {DateTime.UtcNow}.";			}			// Get a reference to the blob client for the new file			var blobClient = containerClient.GetBlobClient(fileName);			// Upload the content to the blob, overwriting if it already exists			using var stream = new MemoryStream(System.Text.Encoding.UTF8.GetBytes(fileContent));			await blobClient.UploadAsync(stream, overwrite: true);			// Log the upload operation			logger.LogInformation($"Uploaded content to blob {fileName} in Blob Storage.");			// Create and return an HTTP response indicating success			var response = req.CreateResponse(HttpStatusCode.OK);			await response.WriteStringAsync($"Content saved to blob {fileName} successfully!");			return response;		}	}}